+          `heap Δ ${(heapAfter - heapBefore).toFixed(2).padStart(7)} MB  ` +
+          `peak ${peakHeap.toFixed(1).padStart(6)} MB`
+      );
+    }
+    console.log();
+  }
+}
+
+run().catch((e) => {
+  console.error(e);
+  process.exit(1);
+});

