+        const val_w = p.tape.get(curr + 1);
+        curr = switch (val_w.tag) {
+            .array_opening, .object_opening => val_w.data.ptr, // past closing bracket
+            .unsigned, .signed, .double => curr + 3, // key + value_tag + number_data
+            else => curr + 2, // key + value
+        };
+    }
