+        // Skip to next key: advance past key + value
+        const val_w = p.tape.get(curr + 1);
+        curr = switch (val_w.tag) {
+            .array_opening, .object_opening => val_w.data.ptr,
+            .unsigned, .signed, .double => curr + 3,
+            else => curr + 2,
+        };
+        i += 1;
+    }
