+/**
+ * Phase 1: Full JSON parsing verification.
+ * Tests all JSON types, nested structures, edge cases,
+ * and correctness vs JSON.parse().
+ */
+import { init } from "../dist/index.js";
+
+let passed = 0, failed = 0;
+async function test(name, fn) {
+  try { await fn(); passed++; console.log(`  ✅ ${name}`); }
+  catch (err) { failed++; console.error(`  ❌ ${name}: ${err.message}`); }
+}
+
+function assertEqual(actual, expected, msg) {
+  const a = JSON.stringify(actual);
+  const e = JSON.stringify(expected);
+  if (a !== e) throw new Error(msg || `Expected ${e}, got ${a}`);
+}
+
+function assertDeepEqual(actual, expected) {
+  assertEqual(JSON.parse(JSON.stringify(actual)), JSON.parse(JSON.stringify(expected)));
+}
+
+console.log("\n🧪 VectorJSON Phase 1 — Full Parse Tests\n");
+const vj = await init();
+
+// --- Scalar types ---
+await test("null", () => assertEqual(vj.parse("null"), null));
+await test("true", () => assertEqual(vj.parse("true"), true));
+await test("false", () => assertEqual(vj.parse("false"), false));
+await test("positive integer", () => assertEqual(vj.parse("42"), 42));
+await test("negative integer", () => assertEqual(vj.parse("-7"), -7));
+await test("zero", () => assertEqual(vj.parse("0"), 0));
+await test("float", () => {
+  const r = vj.parse("3.14159");
+  if (Math.abs(r - 3.14159) > 1e-10) throw new Error(`Got ${r}`);
+});
+await test("exponent notation", () => {
+  const r = vj.parse("1.5e10");
+  if (Math.abs(r - 1.5e10) > 1) throw new Error(`Got ${r}`);
+});
+await test("negative exponent", () => {
+  const r = vj.parse("1e-5");
+  if (Math.abs(r - 1e-5) > 1e-15) throw new Error(`Got ${r}`);
+});
+await test("large integer", () => assertEqual(vj.parse("9007199254740991"), 9007199254740991)); // MAX_SAFE_INTEGER
+await test("simple string", () => assertEqual(vj.parse('"hello"'), "hello"));
+await test("empty string", () => assertEqual(vj.parse('""'), ""));
+await test("string with escapes", () => {
