+await test("string with backslash", () => assertEqual(vj.parse('"a\\\\b"'), "a\\b"));
+await test("string with quote", () => assertEqual(vj.parse('"a\\"b"'), 'a"b'));
+await test("string with unicode", () => assertEqual(vj.parse('"\\u0041"'), "A"));
