+await test("array of ints", () => assertEqual(vj.parse("[1,2,3]"), [1,2,3]));
+await test("array of mixed", () => assertEqual(vj.parse('[1,"a",true,null]'), [1,"a",true,null]));
+await test("nested arrays", () => assertEqual(vj.parse("[[1,2],[3,4]]"), [[1,2],[3,4]]));
+await test("deeply nested arrays", () => assertEqual(vj.parse("[[[1]]]"), [[[1]]]));
