+
+await test("stream: null value", () => {
+  const p = vj.createParser();
+  assertEqual(p.feed("null"), "complete");
+  assertEqual(p.getValue(), null);
+  p.destroy();
+});
+
+// --- NDJSON / end_early ---
+await test("stream: end_early with trailing data", () => {
