+  assert(bigintThrew, "BigInt throws TypeError");
+
+  // --- Round-trip tests ---
+  console.log("\nRound-trip (stringify(parse(x)) === x):");
+
+  const roundTripCases = [
+    '{"hello":"world"}',
+    "[1,2,3]",
+    "null",
+    "true",
+    "false",
+    "42",
+    '"test"',
+    '{"a":{"b":[1,2,{"c":true}]}}',
+    '["nested",["arrays",[1,2,3]]]',
