+  assertEqual(
+    vj.stringify("Hello 世界"),
+    '"Hello 世界"',
+    "CJK characters"
+  );
+  assertEqual(
+    vj.stringify("emoji 🎉"),
+    '"emoji 🎉"',
+    "emoji"
+  );
+  assertEqual(
+    vj.stringify({ "кey": "значение" }),
+    '{"кey":"значение"}',
+    "Cyrillic key and value"
+  );
+
+  // --- Summary ---
+  console.log(`\n${"=".repeat(40)}`);
+  console.log(`Results: ${pass} passed, ${fail} failed out of ${pass + fail}`);
+  if (fail > 0) process.exit(1);
+}
+
+run().catch((e) => {
+  console.error(e);
+  process.exit(1);
+});

