+    "number → string"
+  );
+  assertDiffs(
+    vj.deepCompare({ a: [] }, { a: {} }),
+    [{ path: "$.a", type: "type_changed" }],
+    "array → object"
+  );
+  assertDiffs(
+    vj.deepCompare({ a: null }, { a: 0 }),
+    [{ path: "$.a", type: "type_changed" }],
+    "null → number"
+  );
